const digits = (value="") => String(value).replace(/[٠-٩]/g,d=>"٠١٢٣٤٥٦٧٨٩".indexOf(d)).replace(/[۰-۹]/g,d=>"۰۱۲۳۴۵۶۷۸۹".indexOf(d));
const onlyDigits = (value="") => digits(value).replace(/\D/g,"");
const initials = (name="") => name.split(" ").slice(0,2).map(x=>x[0]||"").join("");
const escapeHtml = (value="") => String(value).replace(/[&<>'"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"}[c]));
const sleep = ms => new Promise(resolve=>setTimeout(resolve,ms));
const AUTH_SESSION_MARKER="rakaez-auth-session-v2";
const IDLE_SESSION_TIMEOUT=15*60*1000;
let sessionTimer=null,lastSessionActivity=0,sessionActivityBound=false;
const countryByName = name => countries.find(x=>x[0]===name) || countries[0];
const countryByDial = dial => supportedCountries.find(x=>x[1]===dial) || supportedCountries[0];
const employeePhotoSrc = employee => employee?.photoDataUrl || employee?.photoUrl || "";
const dialOptions = selected => supportedCountries.map(country=>`<option value="${country[1]}" ${country[1]===selected?"selected":""}>${country[2]} ${country[1]} · ${country[0]}</option>`).join("");
const phoneField = (numberName,dialName,selected="+965",required=false) => `<div class="phone editable-phone"><select name="${dialName}" class="dial-select" aria-label="فتح الخط">${dialOptions(selected)}</select><input name="${numberName}" class="english-number" inputmode="numeric" maxlength="15" placeholder="رقم الهاتف" ${required?"required":""}></div>`;
const durationHours = (from,to) => { const [fh,fm]=from.split(":").map(Number), [th,tm]=to.split(":").map(Number); let minutes=(th*60+tm)-(fh*60+fm); if(minutes<=0) minutes+=1440; return minutes/60; };
const formatHours = n => Number.isInteger(n)?String(n):String(Math.round(n*100)/100);
const timeParts = value => { const [hour24,minute]=value.split(":").map(Number); return {hour:hour24%12||12,minute:minute>=30?"30":"00",period:hour24>=12?"pm":"am"}; };
const timeValue = prefix => { const hour=Number($(`#${prefix}-hour`).value),minute=$(`#${prefix}-minute`).value,period=$(`#${prefix}-period`).value; const hour24=period==="pm"?(hour%12)+12:hour%12; return `${String(hour24).padStart(2,"0")}:${minute}`; };
const formatArabicTime = value => { const parts=timeParts(value); return `${String(parts.hour).padStart(2,"0")}:${parts.minute} ${parts.period==="am"?"صباحاً":"مساءً"}`; };
function timePicker(prefix,value){const parts=timeParts(value);return `<div class="custom-time-picker" dir="ltr"><select id="${prefix}-hour" aria-label="الساعة">${Array.from({length:12},(_,i)=>i+1).map(hour=>`<option value="${hour}" ${hour===parts.hour?"selected":""}>${String(hour).padStart(2,"0")}</option>`).join("")}</select><b>:</b><select id="${prefix}-minute" aria-label="الدقائق"><option value="00" ${parts.minute==="00"?"selected":""}>00</option><option value="30" ${parts.minute==="30"?"selected":""}>30</option></select><select id="${prefix}-period" class="period-select" aria-label="الفترة"><option value="am" ${parts.period==="am"?"selected":""}>صباحاً</option><option value="pm" ${parts.period==="pm"?"selected":""}>مساءً</option></select></div>`;}

function showToast(message){const el=$("#toast");el.innerHTML=`<i>✓</i><div><b>تمت العملية بنجاح</b><p>${escapeHtml(message)}</p></div>`;el.classList.remove("hidden");setTimeout(()=>el.classList.add("hidden"),4500);}
function showError(message){const el=$("#form-message");if(el){el.textContent=message;el.className="form-message error";el.scrollIntoView({behavior:"smooth",block:"center"});}}
function passwordField(id,placeholder=""){return `<div class="password-field"><input id="${id}" type="password" placeholder="${placeholder}" minlength="6" required><button type="button" class="password-toggle" aria-label="إظهار كلمة المرور" aria-pressed="false"><svg viewBox="0 0 24 24"><path d="M2 12s3.5-6 10-6 10 6 10 6-3.5 6-10 6S2 12 2 12z"/><circle cx="12" cy="12" r="3"/></svg></button></div>`;}
function bindPasswordToggles(){document.querySelectorAll(".password-toggle").forEach(button=>button.onclick=()=>{const input=button.previousElementSibling;const visible=input.type==="text";input.type=visible?"password":"text";button.classList.toggle("visible",!visible);button.setAttribute("aria-pressed",String(!visible));button.setAttribute("aria-label",visible?"إظهار كلمة المرور":"إخفاء كلمة المرور");});}

function stopSessionSecurity(){clearTimeout(sessionTimer);sessionTimer=null;}
async function expireSecureSession(){if(!state.user||state.demo)return;stopSessionSecurity();sessionStorage.removeItem(AUTH_SESSION_MARKER);state.sessionExpired=true;await signOut(auth);}
function resetSessionSecurity(){if(!state.user||state.demo)return;lastSessionActivity=Date.now();clearTimeout(sessionTimer);sessionTimer=setTimeout(expireSecureSession,IDLE_SESSION_TIMEOUT);}
function startSessionSecurity(){if(!state.user||state.demo)return;resetSessionSecurity();if(sessionActivityBound)return;sessionActivityBound=true;["pointerdown","keydown","touchstart","scroll"].forEach(eventName=>window.addEventListener(eventName,resetSessionSecurity,{passive:true}));document.addEventListener("visibilitychange",()=>{if(document.hidden||!state.user)return;if(Date.now()-lastSessionActivity>=IDLE_SESSION_TIMEOUT)expireSecureSession();else resetSessionSecurity();});}

async function initialize(){await setPersistence(auth,browserSessionPersistence);onAuthStateChanged(auth,async user=>{if(user&&!state.demo&&sessionStorage.getItem(AUTH_SESSION_MARKER)!=="active"){await signOut(auth);return;}state.user=user;$("#loading").classList.add("hidden");if(user||state.demo){startSessionSecurity();openDashboard();}else{stopSessionSecurity();openAuth();}});}
function openAuth(mode="login"){$("#dashboard").classList.add("hidden");$("#auth-page").classList.remove("hidden");renderAuth(mode);}
function renderAuth(mode="login"){
  const card=$("#auth-card");
  if(mode==="otp"&&state.pendingLogin){card.innerHTML=`<div class="auth-heading"><span>◈</span><h2>تحقق من واتساب</h2></div><form id="otp-form"><label>رمز الدخول<input id="login-code" class="otp-input" inputmode="numeric" maxlength="6" placeholder="— — — — — —" autofocus required></label><p id="form-message" class="form-message hidden"></p><button class="primary wide">تحقق وادخل للنظام</button></form><button id="back-login" class="text-btn wide">العودة إلى تسجيل الدخول</button>`;$("#otp-form").onsubmit=verifyLoginOtp;$("#back-login").onclick=()=>{state.pendingLogin=null;renderAuth("login");};return;}
  if(mode==="register"){card.innerHTML=`<div class="auth-heading"><span>♙</span><h2>إنشاء حساب المنشأة</h2></div><form id="register-form"><label>البريد الإلكتروني<input id="reg-email" type="email" required></label><label>رقم الهاتف الكويتي<div class="phone"><span>🇰🇼 +965</span><input id="reg-phone" inputmode="numeric" maxlength="8" required></div></label><label>كلمة المرور${passwordField("reg-password")}</label><button class="primary wide">إرسال رموز التحقق</button><p id="form-message" class="form-message hidden"></p></form><button id="back-login" class="text-btn wide">لدي حساب بالفعل</button>`;$("#register-form").onsubmit=requestSignup;$("#back-login").onclick=()=>renderAuth("login");bindPasswordToggles();bindEnglishNumbers(card);return;}
  card.innerHTML=`<div class="auth-heading"><span>✓</span><h2>مرحباً بعودتك</h2></div>${state.sessionExpired?'<p class="form-message">انتهت الجلسة لعدم الاستخدام. سجّل الدخول مجدداً للمتابعة.</p>':""}<form id="login-form"><label>البريد الإلكتروني أو رقم الهاتف<input id="identifier" placeholder="name@company.com أو 5XXXXXXX" required></label><label>رمز المرور${passwordField("password","اكتب رمز المرور")}</label><p id="form-message" class="form-message hidden"></p><button class="primary wide">دخول آمن ←</button></form><div class="divider"><span>حساب جديد</span></div><button id="register-btn" class="secondary wide">＋ إنشاء حساب</button><button id="demo-btn" class="text-btn wide">معاينة النظام بدون تسجيل</button>`;
  $("#login-form").onsubmit=beginLogin;$("#register-btn").onclick=()=>renderAuth("register");$("#demo-btn").onclick=()=>{state.demo=true;state.employees=[...samples];openDashboard();};bindPasswordToggles();
}

async function resolveEmail(identifier){if(identifier.includes("@"))return identifier.trim();const phone=onlyDigits(identifier).slice(-8);const snap=await get(ref(db,`phoneDirectory/${phone}`));if(!snap.exists())throw new Error("لم يتم العثور على حساب بهذا الرقم");return snap.val().email;}
async function beginLogin(event){event.preventDefault();const button=event.submitter;button.disabled=true;button.textContent="جارٍ التحقق...";try{const identifier=$("#identifier").value,password=$("#password").value,email=await resolveEmail(identifier);const check=await fetch(`https://identitytoolkit.googleapis.com/v1/accounts:signInWithPassword?key=${CONFIG.firebase.apiKey}`,{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({email,password,returnSecureToken:true})});const identity=await check.json();if(!check.ok)throw new Error("البريد أو رقم الهاتف أو كلمة المرور غير صحيحة");const profile=await fetch(`${CONFIG.firebase.databaseURL}/userProfiles/${identity.localId}.json?auth=${identity.idToken}`).then(r=>r.json());const phone=String(profile?.phone||onlyDigits(identifier));if(phone.length<8)throw new Error("لا يوجد رقم واتساب مسجل لهذا الحساب");const request=await fetch(CONFIG.n8n.loginOtpUrl,{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({phone,email,purpose:"hrms_login"})});const data=await request.json();if(!request.ok||data.ok===false)throw new Error(data.message||"تعذر إرسال رمز الدخول");state.pendingLogin={email,password,phone};renderAuth("otp");}catch(error){showError(error.message||"تعذر تسجيل الدخول");button.disabled=false;button.textContent="دخول آمن ←";}}
async function verifyLoginOtp(event){event.preventDefault();const code=onlyDigits($("#login-code").value),button=event.submitter;button.disabled=true;try{const verify=await fetch(CONFIG.n8n.verifyOtpUrl,{method:"POST",headers:{"content-type":"application/json"},body:JSON.stringify({phone:state.pendingLogin.phone,code,purpose:"hrms_login"})});const data=await verify.json();if(!verify.ok||!data.ok)throw new Error(data.message||"رمز الدخول غير صحيح");sessionStorage.setItem(AUTH_SESSION_MARKER,"active");state.sessionExpired=false;await signInWithEmailAndPassword(auth,state.pendingLogin.email,state.pendingLogin.password);state.pendingLogin=null;}catch(error){sessionStorage.removeItem(AUTH_SESSION_MARKER);showError(error.message);button.disabled=false;}}
async function requestSignup(event){event.preventDefault();if(!CONFIG.n8n.emailOtpUrl||!CONFIG.n8n.whatsappSignupOtpUrl)return showError("لم يتم إعداد بريد الإرسال وإنشاء الحساب بعد. تسجيل الدخول عبر واتساب جاهز.");}

function openDashboard(){$("#auth-page").classList.add("hidden");$("#dashboard").classList.remove("hidden");const identity=state.user?.email||"وضع المعاينة";$("#user-email").textContent=identity;$("#user-avatar").textContent=identity[0]?.toUpperCase()||"م";$("#header-avatar").textContent=identity[0]?.toUpperCase()||"م";renderNav();bindData();renderPage();}
function renderNav(){$("#side-nav").innerHTML=nav.map(item=>item[0]==="separator"?'<div class="nav-separator" aria-hidden="true"></div>':`<button data-page="${item[0]}" class="${state.page===item[0]?"active":""}"><i>${icons[item[2]]}</i><span>${item[1]}</span>${item[0]==="notifications"?"<em>3</em>":""}</button>`).join("");$("#side-nav").querySelectorAll("button").forEach(button=>button.onclick=()=>{state.page=button.dataset.page;renderNav();renderPage();});}
function bindData(){if(state.demo||!state.user||state.bound)return;state.bound=true;onValue(ref(db,"organizations/default/employees"),snap=>{const value=snap.val()||{};state.employees=Object.entries(value).map(([id,v])=>({id,...v}));renderPage();});onValue(ref(db,"organizations/default/workEntities"),snap=>{if(snap.exists())state.entities=Object.values(snap.val());renderPage();});onValue(ref(db,"organizations/default/settings"),snap=>{state.settings={companyLogoUrl:"",companyLogoDataUrl:"",...(snap.val()||{})};renderPage();});onValue(ref(db,"organizations/default/leaves"),snap=>{const value=snap.val()||{};state.leaves=Object.entries(value).map(([id,v])=>({id,...v}));renderPage();});onValue(ref(db,"organizations/default/fingerprintPlaces"),snap=>{state.fingerprintPlaces=Object.entries(snap.val()||{}).map(([id,value])=>({id,...value}));if(state.page==="fingerprint-places"||state.page==="settings")renderPage();});onValue(ref(db,"organizations/default/attendance"),snap=>{state.attendance=snap.val()||{};if(state.page==="attendance")refreshAttendanceReport();});onValue(ref(db,"organizations/default/schedules"),snap=>{state.schedules=snap.val()||{};if(state.page==="attendance")refreshAttendanceReport();});}
function hero(title,_subtitle,button=""){return `<section class="page-hero"><div><span class="eyebrow">قاعدة بيانات الموارد البشرية</span><h1>${title}</h1></div>${button}</section>`;}
function renderPage(){const item=nav.find(x=>x[0]===state.page);const label=item?.[1]||(state.page==="add"?"إدراج موظف":state.page==="profile"?"بيانات الموظف":state.page==="fingerprint-places"?"أماكن البصمة":"الموظفين");$("#page-title").textContent=label;if(state.page==="employees")renderEmployees();else if(state.page==="add")renderEmployeeForm();else if(state.page==="profile")renderEmployeeProfile();else if(state.page==="entities")renderEntities();else if(state.page==="leaves")renderLeaves();else if(state.page==="schedules")renderSchedules();else if(state.page==="attendance")renderAttendanceReport();else if(state.page==="fingerprint-places")renderFingerprintPlaces();else if(state.page==="settings")renderSettings();else renderGeneric(label);window.scrollTo({top:0,behavior:"smooth"});}

function renderEmployees(){
  const list=state.employees.filter(e=>[e.fullName,e.jobTitle,e.workEntity].some(v=>String(v||"").includes(state.search)));
  $("#page-content").innerHTML=`${hero("الموظفون","",'<div class="employee-page-actions"><button id="add-employee" class="primary">＋ إدراج موظف</button></div>')}<div class="toolbar"><label class="search-box">⌕<input id="employee-search" placeholder="ابحث بالاسم أو المسمى أو جهة العمل" value="${escapeHtml(state.search)}"></label><div class="chips"><button class="active">الكل <span>${state.employees.length}</span></button><button>دوام ثابت</button><button>حسب الجدول</button></div></div><div class="employees-grid">${list.length?list.map(employeeCard).join(""):'<div class="empty"><b>لا توجد نتائج</b></div>'}</div>`;
  $("#add-employee").onclick=()=>{state.page="add";state.draftSegments=[];renderNav();renderPage();};
  $("#employee-search").oninput=e=>{state.search=e.target.value;renderEmployees();};
  document.querySelectorAll(".employee-card").forEach(card=>{card.ondblclick=()=>{state.profileEmployeeId=card.dataset.employeeId;state.page="profile";renderPage();};});
  document.querySelectorAll(".employee-card .bell").forEach(button=>button.onclick=event=>event.stopPropagation());
}
function employeeCard(e){const photo=employeePhotoSrc(e);return `<article class="employee-card" data-employee-id="${escapeHtml(e.id)}" tabindex="0"><div class="card-cover"><span class="status ${e.scheduleType||"fixed"}"></span><div class="avatar">${photo?`<img src="${escapeHtml(photo)}" alt="صورة ${escapeHtml(e.fullName)}">`:initials(e.fullName)}</div><button class="bell" aria-label="إشعارات الموظف">${icons.notifications}<span><b>آخر الإشعارات</b><small>طلب تعديل بصمة</small><small>إجازة بانتظار الاعتماد</small></span></button></div><div class="employee-info"><h3>${escapeHtml(e.fullName)}</h3><p>${escapeHtml(e.jobTitle||"")}</p><div class="entity">▥ ${escapeHtml(e.workEntity||"")}</div><footer><span>◷ ${e.dailyHours||0} ساعات</span><em class="${e.scheduleType||"fixed"}">${e.scheduleType==="variable"?"حسب الجدول":"دوام ثابت"}</em></footer></div></article>`;}

function profileDataRow(label,value){return `<div><small>${escapeHtml(label)}</small><b>${escapeHtml(value||"—")}</b></div>`;}
function employeePhoneText(phone){return phone?.phone?`${phone.dialCode||""} ${phone.phone}`.trim():"—";}
function renderEmployeeProfile(){
  const employee=state.employees.find(item=>item.id===state.profileEmployeeId);
  if(!employee){state.page="employees";renderPage();return;}
  const photo=employeePhotoSrc(employee),alternates=employee.alternatePhones||[],relatives=employee.relatives||[],segments=employee.segments||[];
  $("#page-content").innerHTML=`<div class="form-page-heading profile-page-heading"><button id="back-employees" class="back-btn">→</button><div><span>الموظفون / ملف الموظف</span><h1>بيانات ${escapeHtml(employee.fullName)}</h1></div><button id="edit-employee" class="primary">✎ تعديل البيانات وإضافة صورة</button></div><section class="employee-profile"><header class="employee-profile-header"><div class="profile-photo-large">${photo?`<img src="${escapeHtml(photo)}" alt="صورة ${escapeHtml(employee.fullName)}">`:`<span>${initials(employee.fullName)}</span>`}</div><div><span class="eyebrow">ملف الموظف</span><h2>${escapeHtml(employee.fullName)}</h2><p>${escapeHtml(employee.jobTitle||"المسمى الوظيفي غير محدد")}</p><em class="${employee.scheduleType||"fixed"}">${employee.scheduleType==="variable"?"ساعات متغيرة حسب الجدول":"ساعات عمل ثابتة"}</em></div><dl><div><dt>ساعات العمل</dt><dd>${formatHours(Number(employee.dailyHours)||0)} ساعة / يوم</dd></div><div><dt>رمز البصمة</dt><dd>${employee.attendancePin?"••••"+String(employee.attendancePin).slice(-2):"غير محدد"}</dd></div></dl></header><div class="profile-sections"><section><h3>البيانات الأساسية</h3><div class="profile-data-grid">${profileDataRow("الاسم الكامل",employee.fullName)}${profileDataRow("الرقم المدني",employee.civilId)}${profileDataRow("الجنسية",employee.nationality)}${profileDataRow("المسمى الوظيفي",employee.jobTitle)}${profileDataRow("جهة العمل",employee.workEntity)}</div></section><section><h3>معلومات التواصل</h3><div class="profile-data-grid">${profileDataRow("رقم الهاتف الشخصي",employeePhoneText(employee.primaryPhone))}${alternates.map((phone,index)=>profileDataRow(`رقم الهاتف الاحتياطي ${index+1}`,employeePhoneText(phone))).join("")||profileDataRow("الأرقام الاحتياطية","لا توجد أرقام مضافة")}</div>${relatives.length?`<div class="profile-relatives">${relatives.map((relative,index)=>`<div><b>القريب ${index+1}</b><span>${escapeHtml(relative.relation||"صلة القرابة غير محددة")}</span><small>${escapeHtml(employeePhoneText(relative))}</small></div>`).join("")}</div>`:""}</section><section><h3>ساعات العمل</h3><div class="profile-data-grid">${profileDataRow("عدد ساعات العمل",`${formatHours(Number(employee.dailyHours)||0)} ساعات / يوم`)}${profileDataRow("طريقة الدوام",employee.scheduleType==="variable"?"حسب جدول الدوامات":"ساعات عمل ثابتة")}${profileDataRow("فترات العمل الثابتة",segments.length?`${segments.length} فترات`:"لم يتم توزيع المهام")}</div></section></div></section>`;
  $("#back-employees").onclick=()=>{state.page="employees";state.profileEmployeeId=null;renderPage();};
  $("#edit-employee").onclick=()=>openEmployeeEditor(employee.id);
}

async function readEmployeePhoto(file){
  if(!file)return "";
  if(!file.type.startsWith("image/"))throw new Error("يرجى اختيار صورة بصيغة PNG أو JPG أو WEBP.");
  if(file.size>6*1024*1024)throw new Error("حجم الصورة كبير جداً. اختر صورة أقل من 6 ميغابايت.");
  const objectUrl=URL.createObjectURL(file);
  try{
    const image=await new Promise((resolve,reject)=>{const img=new Image();img.onload=()=>resolve(img);img.onerror=()=>reject(new Error("تعذر قراءة الصورة."));img.src=objectUrl;});
    let width=Math.min(image.naturalWidth||640,700),height=Math.round((image.naturalHeight||640)*width/(image.naturalWidth||640)),quality=.86,dataUrl="";
    for(let attempt=0;attempt<5;attempt++){
      const canvas=document.createElement("canvas");canvas.width=width;canvas.height=height;
      canvas.getContext("2d").drawImage(image,0,0,width,height);
      dataUrl=canvas.toDataURL("image/jpeg",quality);
      if(dataUrl.length<800000)break;
      width=Math.round(width*.78);height=Math.round(height*.78);quality=Math.max(.62,quality-.07);
    }
    if(dataUrl.length>=800000)throw new Error("تعذر ضغط الصورة للحجم المناسب. اختر صورة أصغر.");
    return dataUrl;
  }finally{URL.revokeObjectURL(objectUrl);}
}

function editorCountryOptions(selected=""){return supportedCountries.map(country=>`<option value="${country[0]}" ${country[0]===selected?"selected":""}>${country[2]} ${country[0]}</option>`).join("");}
function openEmployeeEditor(employeeId){
  const employee=state.employees.find(item=>item.id===employeeId);if(!employee)return;
  const photo=employeePhotoSrc(employee),root=$("#modal-root"),primary=employee.primaryPhone||{},altPhones=employee.alternatePhones||[];
  root.innerHTML=`<div class="modal-backdrop employee-editor-backdrop"><section class="modal employee-editor-modal" role="dialog" aria-modal="true" aria-labelledby="employee-editor-title"><header><div><span>ملف الموظف</span><h3 id="employee-editor-title">تعديل بيانات ${escapeHtml(employee.fullName)}</h3></div><button type="button" class="modal-close" aria-label="إغلاق">×</button></header><form id="employee-editor-form"><div class="editor-photo-row"><label class="editor-photo-picker"><input id="editor-photo" type="file" accept="image/png,image/jpeg,image/webp"><span id="editor-photo-preview">${photo?`<img src="${escapeHtml(photo)}" alt="">`:initials(employee.fullName)}</span><b>تغيير الصورة الشخصية</b></label></div><div class="editor-grid"><label>الاسم الكامل<input name="fullName" value="${escapeHtml(employee.fullName)}" required></label><label>الرقم المدني<input name="civilId" class="english-number" inputmode="numeric" maxlength="12" value="${escapeHtml(employee.civilId||"")}" required></label><label>الجنسية<select name="nationality"><option value="">اختر الجنسية</option>${editorCountryOptions(employee.nationality||"")}</select></label><label>المسمى الوظيفي<input name="jobTitle" value="${escapeHtml(employee.jobTitle||"")}" required></label><label class="wide-field">جهة العمل<select name="workEntity" required><option value="">اختر جهة العمل</option>${state.entities.map(entity=>`<option ${entity===employee.workEntity?"selected":""}>${escapeHtml(entity)}</option>`).join("")}</select></label><label>رقم الهاتف الشخصي${phoneField("primaryPhone","primaryDial",primary.dialCode||"+965")}</label><label>عدد ساعات العمل<input name="dailyHours" class="english-number" inputmode="decimal" value="${escapeHtml(employee.dailyHours||8)}" required></label><label>رمز دخول البصمة<input name="attendancePin" class="english-number" inputmode="numeric" minlength="4" maxlength="8" value="${escapeHtml(employee.attendancePin||"")}" required></label><label>طريقة الدوام<select name="scheduleType"><option value="variable" ${employee.scheduleType==="variable"?"selected":""}>حسب جدول الدوامات</option><option value="fixed" ${employee.scheduleType!=="variable"?"selected":""}>ساعات عمل ثابتة</option></select></label></div><p id="employee-editor-error" class="form-message error hidden"></p><footer><button type="button" class="secondary modal-cancel">إلغاء</button><button class="primary">حفظ التعديلات</button></footer></form></section></div>`;
  root.querySelector('[name="primaryPhone"]').value=primary.phone||"";
  const close=()=>root.innerHTML="";
  $(".modal-close").onclick=$(".modal-cancel").onclick=close;
  $(".employee-editor-backdrop").onclick=event=>{if(event.target.classList.contains("employee-editor-backdrop"))close();};
  bindEnglishNumbers(root);
  let nextPhotoDataUrl=employee.photoDataUrl||"";
  $("#editor-photo").onchange=async event=>{const file=event.target.files?.[0];if(!file)return;try{nextPhotoDataUrl=await readEmployeePhoto(file);$("#editor-photo-preview").innerHTML=`<img src="${escapeHtml(nextPhotoDataUrl)}" alt="معاينة الصورة">`;}catch(error){const message=$("#employee-editor-error");message.textContent=error.message;message.classList.remove("hidden");}};
  $("#employee-editor-form").onsubmit=async event=>{
    event.preventDefault();const form=event.target,data=Object.fromEntries(new FormData(form)),error=$("#employee-editor-error"),attendancePin=onlyDigits(data.attendancePin),primaryPhone=onlyDigits(data.primaryPhone),dailyHours=Number(data.dailyHours);
    if(attendancePin.length<4||attendancePin.length>8){error.textContent="رمز دخول البصمة يجب أن يتكون من 4 إلى 8 أرقام.";error.classList.remove("hidden");return;}
    if(!dailyHours||dailyHours>24){error.textContent="أدخل عدد ساعات عمل صحيحاً من 1 إلى 24.";error.classList.remove("hidden");return;}
    if(state.employees.some(item=>item.id!==employee.id&&String(item.attendancePin||"")===attendancePin)){error.textContent="رمز دخول البصمة مستخدم لموظف آخر.";error.classList.remove("hidden");return;}
    const previousPin=String(employee.attendancePin||""),record={...employee,fullName:data.fullName.trim(),civilId:onlyDigits(data.civilId),nationality:data.nationality||"",jobTitle:data.jobTitle.trim(),workEntity:data.workEntity,dailyHours,scheduleType:data.scheduleType,attendancePin,primaryPhone:primaryPhone?{phone:primaryPhone,dialCode:data.primaryDial,country:countryByDial(data.primaryDial)[0]}:null,photoDataUrl:nextPhotoDataUrl,photoUrl:nextPhotoDataUrl?"":employee.photoUrl||"",updatedAt:Date.now()};
    try{
      if(state.demo){state.employees=state.employees.map(item=>item.id===employee.id?record:item);}else if(state.user){
        if(previousPin!==attendancePin){const pinRef=ref(db,`organizations/default/attendancePins/${attendancePin}`),reservation=await runTransaction(pinRef,current=>current===null||current===employee.id?employee.id:undefined,{applyLocally:false});if(!reservation.committed)throw new Error("رمز دخول البصمة مستخدم لموظف آخر.");if(previousPin)await remove(ref(db,`organizations/default/attendancePins/${previousPin}`)).catch(()=>{});}
        await set(ref(db,`organizations/default/employees/${employee.id}`),record);
      }
      state.profileEmployeeId=employee.id;close();showToast(`تم تعديل بيانات ${record.fullName}`);renderEmployeeProfile();
    }catch(saveError){error.textContent=saveError.message||"تعذر حفظ التعديلات.";error.classList.remove("hidden");}
  };
}

function renderEmployeeForm(){
  state.draftSegments=[];
  $("#page-content").innerHTML=`<div class="form-page-heading"><button id="back-employees" class="back-btn">→</button><div><span>الموظفون / إدراج موظف</span><h1>إدراج موظف جديد</h1></div></div><form id="employee-form" class="employee-form" novalidate>
  <section><div class="section-head"><span>01</span><div><h3>بيانات الموظف الأساسية</h3></div></div><label class="photo-upload"><input id="photo" type="file" accept="image/png,image/jpeg,image/webp"><span class="photo-preview">＋</span><b>إدراج صورة عرض</b></label><div class="form-grid"><label>اسم الموظف *<input name="fullName" autocomplete="name" required></label><label>الرقم المدني *<input name="civilId" class="english-number" inputmode="numeric" maxlength="12" required></label><label>الجنسية<div class="search-select"><input id="nationality" name="nationality" list="countries-list" autocomplete="off" placeholder="اختر الجنسية"><span>⌄</span><datalist id="countries-list">${supportedCountries.map(c=>`<option value="${c[0]}">${c[2]} ${c[0]}</option>`).join("")}</datalist></div></label><label>المسمى الوظيفي *<input name="jobTitle" required></label><label class="wide-field">جهة العمل *<select name="workEntity" required><option value="">اختر جهة العمل</option>${state.entities.map(e=>`<option>${escapeHtml(e)}</option>`).join("")}</select></label><label class="wide-field attendance-pin-field">رمز دخول البصمة *${attendancePinField()}</label></div></section>
  <section><div class="section-head"><span>02</span><div><h3>معلومات التواصل الشخصية</h3></div></div><div class="employee-phones-group"><div class="primary-phone-row"><div class="primary-phone-block"><label>رقم الهاتف الشخصي${phoneField("primaryPhone","primaryDial")}</label></div><button type="button" id="add-alternate-phone" class="circle-add" aria-label="إضافة رقم هاتف احتياطي" title="إضافة رقم هاتف احتياطي">＋</button></div><div id="alternate-phones" class="alternate-phones"></div></div><div class="relatives-head"><div><h4>أرقام هواتف أقرب الأشخاص</h4></div><button type="button" id="add-relative" class="circle-add" aria-label="إضافة قريب">＋</button></div><div id="relatives-list" class="relatives-list"></div></section>
  <section><div class="section-head"><span>03</span><div><h3>ساعات العمل وتوزيع المهام</h3></div></div><div class="hours-row"><label>عدد ساعات العمل للموظف *<div class="hours-input"><input id="daily-hours" name="dailyHours" class="english-number" inputmode="decimal" value="8" required><span>ساعة / يوم</span></div></label><fieldset class="schedule-choice"><legend>طريقة الدوام *</legend><label><input type="radio" name="scheduleType" value="variable" checked><span><i>▦</i><b>حسب جدول الدوامات</b></span></label><label><input type="radio" name="scheduleType" value="fixed"><span><i>✓</i><b>ساعات عمل ثابتة</b></span></label></fieldset></div><div id="fixed-schedule" class="fixed-schedule hidden"><div class="distribution-title"><div><h4>توزيع ساعات العمل</h4></div><strong id="distribution-count">0 من 8 ساعات</strong></div><div class="timeline-row"><button type="button" id="add-segment" class="timeline-add" aria-label="إضافة فترة">＋</button><div id="work-timeline" class="work-timeline"></div></div></div></section>
  <p id="form-message" class="form-message hidden"></p><div class="form-actions"><button type="button" id="cancel-employee" class="secondary">إلغاء</button><button class="primary submit">＋ إضافة الموظف</button></div></form>`;
  bindEmployeeForm();
}

function bindEnglishNumbers(root=document){root.querySelectorAll(".english-number").forEach(input=>input.addEventListener("input",()=>{const allowDecimal=input.classList.contains("decimal-number")||input.id==="daily-hours"||input.name==="dailyHours";let value=digits(input.value).replace(allowDecimal?/[^0-9.]/g:/\D/g,"");if(allowDecimal){const parts=value.split(".");value=parts.shift()+(parts.length?"."+parts.join(""):"");}input.value=value;}));}
function attendancePinField(){return `<div class="attendance-pin-slots" data-attendance-pin><input name="attendancePin" class="english-number pin-input" inputmode="numeric" minlength="4" maxlength="8" autocomplete="off" aria-label="رمز دخول البصمة" required><div class="pin-slot-display" aria-hidden="true"></div></div>`;}
function updateAttendancePinMask(box){const input=box.querySelector("input"),value=onlyDigits(input.value).slice(0,8),slotCount=Math.max(4,value.length);input.value=value;box.querySelector(".pin-slot-display").innerHTML=Array.from({length:slotCount},(_,index)=>`<span class="${index<value.length?"filled":""}">${value[index]||"—"}</span>`).join("");}
function bindAttendancePinMask(root=document){root.querySelectorAll("[data-attendance-pin]").forEach(box=>{const input=box.querySelector("input");updateAttendancePinMask(box);input.addEventListener("input",()=>updateAttendancePinMask(box));box.addEventListener("click",()=>input.focus());});}
function addAlternatePhoneRow(){const list=$("#alternate-phones"),index=list.children.length;const row=document.createElement("div");row.className="alternate-phone-row";row.innerHTML=`<label>رقم الهاتف الاحتياطي ${index+1}${phoneField("alternatePhone","alternateDial")}</label><button type="button" class="remove-relative" aria-label="حذف الرقم الاحتياطي">×</button>`;list.appendChild(row);row.querySelector(".remove-relative").onclick=()=>{row.remove();renumberAlternatePhones();};bindEnglishNumbers(row);}
function renumberAlternatePhones(){document.querySelectorAll(".alternate-phone-row").forEach((row,i)=>row.querySelector("label").childNodes[0].textContent=`رقم الهاتف الاحتياطي ${i+1}`);}
function addRelativeRow(){const list=$("#relatives-list"),index=list.children.length;const row=document.createElement("div");row.className="relative-row";row.innerHTML=`<label>الرقم ${index+1}${phoneField("relativePhone","relativeDial")}</label><label>نوع القرابة<input name="relation" placeholder="مثال: الأب، الزوجة، الأخ"></label>${index?'<button type="button" class="remove-relative" aria-label="حذف الرقم">×</button>':'<span></span>'}`;list.appendChild(row);row.querySelector(".remove-relative")?.addEventListener("click",()=>{row.remove();renumberRelatives();});bindEnglishNumbers(row);}
function renumberRelatives(){document.querySelectorAll(".relative-row").forEach((row,i)=>row.querySelector("label").childNodes[0].textContent=`الرقم ${i+1}`);}
function bindEmployeeForm(){
  $("#back-employees").onclick=$("#cancel-employee").onclick=()=>{state.page="employees";renderNav();renderPage();};
  $("#photo").onchange=e=>{const file=e.target.files[0];if(!file)return;const preview=$(".photo-preview");preview.innerHTML=`<img src="${URL.createObjectURL(file)}" alt="معاينة الصورة">`;preview.parentElement.classList.add("has-photo");};
  $("#add-alternate-phone").onclick=addAlternatePhoneRow;
  $("#add-relative").onclick=addRelativeRow;addRelativeRow();
  bindEnglishNumbers($("#employee-form"));
  bindAttendancePinMask($("#employee-form"));
  document.querySelectorAll('input[name="scheduleType"]').forEach(input=>input.onchange=()=>{$("#fixed-schedule").classList.toggle("hidden",input.value!=="fixed"||!input.checked);});
  $("#daily-hours").oninput=()=>{const input=$("#daily-hours");input.value=digits(input.value).replace(/[^0-9.]/g,"");const total=Number(input.value)||0;const used=state.draftSegments.reduce((sum,s)=>sum+s.hours,0);if(used>total)state.draftSegments=[];renderTimeline();};
  $("#add-segment").onclick=()=>openSegmentModal();renderTimeline();
  $("#employee-form").onsubmit=saveEmployee;
}

function renderTimeline(){const total=Number($("#daily-hours")?.value)||0,used=state.draftSegments.reduce((sum,s)=>sum+s.hours,0),remaining=Math.max(0,total-used),timeline=$("#work-timeline");if(!timeline)return;const colors=["#0f766e","#2563a8","#c58a2c","#7b5cab","#be5b70","#2f8f63"];timeline.innerHTML=state.draftSegments.map((s,i)=>`<button type="button" class="timeline-segment" data-index="${i}" style="flex:${s.hours};background:${colors[i%colors.length]}" title="تعديل الفترة"><b>${formatArabicTime(s.from)} — ${formatArabicTime(s.to)}</b><span>${s.tasks.map(escapeHtml).join(" <i>＋</i> ")}</span><em>${formatHours(s.hours)} س</em></button>`).join("")+(remaining?`<div class="timeline-remaining" style="flex:${remaining}"><b>${formatHours(remaining)} ساعات متبقية</b><span>لم يتم توزيعها بعد</span></div>`:"");if(!total)timeline.innerHTML='<div class="timeline-remaining" style="flex:1"><b>أدخل عدد ساعات العمل</b></div>';$("#distribution-count").textContent=`${formatHours(used)} من ${formatHours(total)} ساعات`;$("#timeline-help").textContent=remaining?`متبقي ${formatHours(remaining)} ساعات لإكمال التوزيع`:"اكتمل توزيع جميع ساعات العمل ✓";$("#timeline-help").classList.toggle("complete",Boolean(total&&!remaining));$("#add-segment").disabled=!total||remaining<=0;timeline.querySelectorAll(".timeline-segment").forEach(button=>button.onclick=()=>openSegmentModal(Number(button.dataset.index)));}
function openSegmentModal(editIndex=null){const editing=editIndex!==null,segment=editing?state.draftSegments[editIndex]:{from:"08:00",to:"14:00",tasks:[""]};$("#modal-root").innerHTML=`<div class="modal-backdrop"><section class="modal work-segment-modal" role="dialog" aria-modal="true" aria-labelledby="segment-title"><header><div><span>توزيع ساعات العمل</span><h3 id="segment-title">${editing?"تعديل فترة العمل":"إضافة فترة عمل جديدة"}</h3></div><button type="button" class="modal-close" aria-label="إغلاق">×</button></header><form id="segment-form"><div class="time-grid"><label>من الساعة${timePicker("segment-from",segment.from)}</label><span>←</span><label>إلى الساعة${timePicker("segment-to",segment.to)}</label></div><div class="modal-duration">مدة الفترة: <b id="segment-duration">${formatHours(durationHours(segment.from,segment.to))} ساعات</b></div><div class="tasks-head"><label>مهام العمل</label><button type="button" id="add-task" class="mini-add">＋ مهمة إضافية</button></div><div id="tasks-list">${segment.tasks.map((task,i)=>taskInput(task,i)).join("")}</div><p id="segment-error" class="form-message error hidden"></p><footer>${editing?'<button type="button" id="delete-segment" class="danger-btn">حذف الفترة</button>':'<span></span>'}<div><button type="button" class="secondary modal-cancel">إلغاء</button><button class="primary">${editing?"حفظ التعديلات":"إضافة إلى توزيع المهام"}</button></div></footer></form></section></div>`;
  const close=()=>{$("#modal-root").innerHTML="";};$(".modal-close").onclick=$(".modal-cancel").onclick=close;$(".modal-backdrop").onclick=e=>{if(e.target.classList.contains("modal-backdrop"))close();};$("#add-task").onclick=()=>{$("#tasks-list").insertAdjacentHTML("beforeend",taskInput("",$("#tasks-list").children.length));bindTaskRemovers();};bindTaskRemovers();const updateDuration=()=>{$("#segment-duration").textContent=`${formatHours(durationHours(timeValue("segment-from"),timeValue("segment-to")))} ساعات`;};document.querySelectorAll(".custom-time-picker select").forEach(select=>select.onchange=updateDuration);
  if(editing)$("#delete-segment").onclick=()=>{state.draftSegments.splice(editIndex,1);close();renderTimeline();};
  $("#segment-form").onsubmit=e=>{e.preventDefault();const from=timeValue("segment-from"),to=timeValue("segment-to"),hours=durationHours(from,to),tasks=[...document.querySelectorAll('.task-input input')].map(x=>x.value.trim()).filter(Boolean),total=Number($("#daily-hours").value),otherUsed=state.draftSegments.reduce((sum,s,i)=>sum+(i===editIndex?0:s.hours),0);if(!tasks.length)return segmentError("أضف مهمة عمل واحدة على الأقل.");if(otherUsed+hours>total+0.001)return segmentError(`مدة الفترة أكبر من الساعات المتبقية (${formatHours(total-otherUsed)} ساعات).`);const record={from,to,hours,tasks};if(editing)state.draftSegments[editIndex]=record;else state.draftSegments.push(record);close();renderTimeline();};
}
function taskInput(value,index){return `<div class="task-input"><span>${index+1}</span><input value="${escapeHtml(value)}" placeholder="اكتب مهمة العمل" required>${index?'<button type="button" aria-label="حذف المهمة">×</button>':'<i></i>'}</div>`;}
function bindTaskRemovers(){document.querySelectorAll(".task-input button").forEach(button=>button.onclick=()=>{button.parentElement.remove();document.querySelectorAll(".task-input").forEach((row,i)=>row.querySelector("span").textContent=i+1);});}
function segmentError(message){const el=$("#segment-error");el.textContent=message;el.classList.remove("hidden");}

async function saveEmployee(event){
  event.preventDefault();const form=event.target,button=event.submitter,data=Object.fromEntries(new FormData(form)),dailyHours=Number(data.dailyHours),attendancePin=onlyDigits(data.attendancePin),primaryNumber=onlyDigits(data.primaryPhone);
  if(!form.checkValidity()){form.reportValidity();return showError("يرجى إكمال جميع الحقول المطلوبة.");}
  if(attendancePin.length<4||attendancePin.length>8)return showError("رمز دخول البصمة يجب أن يتكون من 4 إلى 8 أرقام.");
  if(!dailyHours||dailyHours>24)return showError("أدخل عدد ساعات عمل صحيحًا من 1 إلى 24.");
  if(data.nationality&&!supportedCountries.some(country=>country[0]===data.nationality))return showError("اختر جنسية من قائمة الجنسيات المتاحة أو اترك الحقل فارغاً.");
  if(primaryNumber&&data.primaryDial==="+965"&&primaryNumber.length!==8)return showError("رقم الهاتف الشخصي الكويتي يجب أن يتكون من 8 أرقام.");
  if(primaryNumber&&data.primaryDial!=="+965"&&(primaryNumber.length<6||primaryNumber.length>15))return showError("أدخل رقم هاتف شخصي صحيحاً أو اترك الحقل فارغاً.");
  if(state.employees.some(employee=>String(employee.attendancePin||"")===attendancePin))return showError("رمز دخول البصمة مستخدم لموظف آخر، اختر رمزًا مختلفًا.");
  button.disabled=true;const id=crypto.randomUUID(),pinRef=ref(db,`organizations/default/attendancePins/${attendancePin}`);let pinReserved=false,photoDataUrl="";$("#action-loading").classList.remove("hidden");
  try{if(!state.demo&&state.user){const reservation=await runTransaction(pinRef,current=>current===null?id:undefined,{applyLocally:false});if(!reservation.committed)throw new Error("رمز دخول البصمة مستخدم لموظف آخر، اختر رمزًا مختلفًا.");pinReserved=true;}const file=$("#photo").files[0];if(file)photoDataUrl=await readEmployeePhoto(file);const alternatePhones=[...form.querySelectorAll(".alternate-phone-row")].map(row=>({phone:onlyDigits(row.querySelector('[name="alternatePhone"]').value),dialCode:row.querySelector('[name="alternateDial"]').value,country:countryByDial(row.querySelector('[name="alternateDial"]').value)[0]})).filter(item=>item.phone);const relatives=[...form.querySelectorAll(".relative-row")].map(row=>({phone:onlyDigits(row.querySelector('[name="relativePhone"]').value),dialCode:row.querySelector('[name="relativeDial"]').value,country:countryByDial(row.querySelector('[name="relativeDial"]').value)[0],relation:row.querySelector('[name="relation"]').value.trim()})).filter(item=>item.phone);const record={id,fullName:data.fullName.trim(),civilId:onlyDigits(data.civilId),nationality:data.nationality||"",jobTitle:data.jobTitle.trim(),workEntity:data.workEntity,attendancePin,dailyHours,scheduleType:data.scheduleType,segments:data.scheduleType==="fixed"?[...state.draftSegments]:[],primaryPhone:primaryNumber?{phone:primaryNumber,dialCode:data.primaryDial,country:countryByDial(data.primaryDial)[0]}:null,alternatePhones,relatives,photoUrl:"",photoDataUrl,profileCompleted:false,createdAt:Date.now()};if(state.demo||!state.user)state.employees.unshift(record);else await set(ref(db,`organizations/default/employees/${id}`),record);await sleep(1200);$("#action-loading").classList.add("hidden");showToast(`تم إدراج الموظف ${record.fullName} وربط رمز البصمة بنجاح`);state.page="employees";renderNav();renderPage();}catch(error){if(pinReserved)await remove(pinRef).catch(()=>{});$("#action-loading").classList.add("hidden");showError(error.message||"تعذر إدراج الموظف");button.disabled=false;}
}

const arabicWeekdays=["الأحد","الاثنين","الثلاثاء","الأربعاء","الخميس","الجمعة","السبت"];
const localDateKey=date=>`${date.getFullYear()}-${String(date.getMonth()+1).padStart(2,"0")}-${String(date.getDate()).padStart(2,"0")}`;
const dateFromKey=key=>{const [year,month,day]=String(key).split("-").map(Number);return new Date(year,month-1,day,12);};
const leaveTypeLabel=leave=>leave?.type==="weekly"?"إجازة أسبوعية":leave?.type==="sick"?"إجازة مرضية":leave?.type==="annual"?"إجازة سنوية":"إجازة";
const leaveDateText=key=>{const date=dateFromKey(key);return `${arabicWeekdays[date.getDay()]} ${date.getDate()}-${date.getMonth()+1}-${date.getFullYear()}`;};
function currentWeekDates(){const now=new Date(),start=new Date(now);start.setHours(12,0,0,0);start.setDate(now.getDate()-((now.getDay()-6+7)%7));return Array.from({length:7},(_,index)=>{const date=new Date(start);date.setDate(start.getDate()+index);return{key:localDateKey(date),name:arabicWeekdays[date.getDay()],date};});}
function leaveForEmployeeToday(employeeId){const today=localDateKey(new Date());return state.leaves.find(leave=>leave.employeeId===employeeId&&leave.startDate<=today&&leave.endDate>=today);}
function employeeLeaveSummary(employee){const leave=leaveForEmployeeToday(employee.id);return leave?`<span class="leave-current-status ${leave.duration==="half"?"half":"full"}">${escapeHtml(leaveTypeLabel(leave))}${leave.duration==="half"?" · نصف يوم":""}</span>`:"";}
function calculateLeaveEnd(startDate,totalDays,skipDay){let date=dateFromKey(startDate),remaining=Math.max(1,Math.round(Number(totalDays)||1));while(remaining>0){if(skipDay===null||date.getDay()!==Number(skipDay))remaining--;if(remaining===0)return localDateKey(date);date.setDate(date.getDate()+1);}return startDate;}
function leaveWeeksOptions(selected=""){return currentWeekDates().map(day=>`<option value="${day.key}" ${day.key===selected?"selected":""}>${day.name} · ${leaveDateText(day.key)}</option>`).join("");}
function weekdayOptions(selected=5){return arabicWeekdays.map((day,index)=>`<option value="${index}" ${Number(selected)===index?"selected":""}>${day}</option>`).join("");}

function renderLeaves(){
  const employees=[...state.employees].sort((a,b)=>String(a.fullName||"").localeCompare(String(b.fullName||""),"ar"));
  $("#page-content").innerHTML=`<section class="leaves-page"><div class="leaves-heading"><div><span class="eyebrow">إدارة الإجازات</span><h1>إجازات الموظفين</h1></div><span>${employees.length} موظف</span></div><section class="leaves-list-card"><header><div><h2>قائمة الموظفين</h2></div><i>⌁</i></header><div class="leave-employees-grid">${employees.length?employees.map(employee=>`<article class="leave-employee"><div class="leave-person"><span class="leave-avatar">${employeePhotoSrc(employee)?`<img src="${escapeHtml(employeePhotoSrc(employee))}" alt="">`:initials(employee.fullName)}</span><div><b>${escapeHtml(employee.fullName)}</b><small>${escapeHtml(employee.jobTitle||"المسمى الوظيفي غير محدد")}</small>${employeeLeaveSummary(employee)}</div></div><div class="leave-actions"><button class="weekly-leave-button" data-weekly-leave="${escapeHtml(employee.id)}"><i>＋</i> إجازة أسبوعية</button><button class="special-leave-button" data-special-leave="${escapeHtml(employee.id)}">إجازة خاصة</button></div></article>`).join(""):'<div class="empty"><b>لا يوجد موظفون بعد</b></div>'}</div></section></section>`;
  document.querySelectorAll("[data-weekly-leave]").forEach(button=>button.onclick=()=>openWeeklyLeaveModal(button.dataset.weeklyLeave));
  document.querySelectorAll("[data-special-leave]").forEach(button=>button.onclick=()=>openSpecialLeaveModal(button.dataset.specialLeave));
}

