  const root=$("#modal-root"),firstDay=currentWeekDates()[0]?.key||localDateKey(new Date());
  root.innerHTML=`<div class="modal-backdrop leave-modal-backdrop"><section class="modal leave-modal" role="dialog" aria-modal="true" aria-labelledby="weekly-leave-title"><header><div><span>إجازة أسبوعية</span><h3 id="weekly-leave-title">إجازة ${escapeHtml(employee.fullName)}</h3></div><button type="button" class="modal-close" aria-label="إغلاق">×</button></header><form id="weekly-leave-form" class="leave-form"><fieldset class="leave-duration-choice"><legend>نوع الإجازة</legend><label><input type="radio" name="weeklyDuration" value="full" checked><span><b>يوم كامل</b></span></label><label><input type="radio" name="weeklyDuration" value="half"><span><b>نصف يوم</b></span></label></fieldset><label>اختر يوم الإجازة<select id="weekly-leave-date">${leaveWeeksOptions(firstDay)}</select></label><footer><span></span><div><button type="button" class="secondary modal-cancel">إلغاء</button><button class="primary">اعتماد الإجازة</button></div></footer></form></section></div>`;
