  bindLeaveModalClose("leave-modal-backdrop");bindEnglishNumbers(root);
  $("#special-leave-start").onsubmit=event=>{event.preventDefault();const value=Number($("#special-leave-period").value),error=$("#special-leave-error");if(!value||value<=0){error.textContent="اكتب مدة الإجازة بصورة صحيحة.";error.classList.remove("hidden");return;}openSpecialLeaveDateStep(employee,{type:$("#special-leave-type").value,value,unit:$("#special-leave-unit").value});};
