function openSpecialLeaveDateStep(employee,details){
  const root=$("#modal-root"),defaultStart=localDateKey(new Date()),totalDays=details.unit==="months"?details.value*30:details.value;
  root.innerHTML=`<div class="modal-backdrop leave-modal-backdrop"><section class="modal leave-modal" role="dialog" aria-modal="true" aria-labelledby="special-date-title"><header><div><span>${details.type==="sick"?"إجازة مرضية":"إجازة سنوية"}</span><h3 id="special-date-title">تحديد فترة الإجازة</h3></div><button type="button" class="modal-close" aria-label="إغلاق">×</button></header><form id="special-leave-date-form" class="leave-form"><label>تاريخ بدء الإجازة<input id="special-leave-start-date" type="date" value="${defaultStart}" required></label><div class="leave-date-preview"><b>بداية الإجازة</b><span id="leave-start-preview"></span></div><label id="skip-weekday-line" class="leave-skip-line"><input id="skip-weekday-enabled" type="checkbox" checked><span>تخطي أيام <select id="skip-weekday">${weekdayOptions(5)}</select> من الحساب</span></label><div class="leave-date-preview end"><b>تاريخ انتهاء الإجازة</b><span id="leave-end-preview"></span></div><footer><span></span><div><button type="button" class="secondary modal-cancel">إلغاء</button><button class="primary">اعتماد الإجازة</button></div></footer></form></section></div>`;
  bindLeaveModalClose("leave-modal-backdrop");
  const updatePreview=()=>{const startDate=$("#special-leave-start-date").value||defaultStart,skipEnabled=$("#skip-weekday-enabled").checked,skipDay=skipEnabled?Number($("#skip-weekday").value):null,endDate=calculateLeaveEnd(startDate,totalDays,skipDay);$("#leave-start-preview").textContent=leaveDateText(startDate);$("#leave-end-preview").textContent=leaveDateText(endDate);$("#skip-weekday-line").classList.toggle("disabled",!skipEnabled);return{startDate,endDate,skipDay};};
  $("#special-leave-start-date").onchange=updatePreview;$("#skip-weekday").onchange=updatePreview;$("#skip-weekday-enabled").onchange=updatePreview;updatePreview();
  $("#special-leave-date-form").onsubmit=event=>{event.preventDefault();const dates=updatePreview();saveLeave({id:crypto.randomUUID(),employeeId:employee.id,type:details.type,duration:"full",startDate:dates.startDate,endDate:dates.endDate,leaveDays:Math.round(totalDays),skipWeekday:dates.skipDay,skipEnabled:$("#skip-weekday-enabled").checked,durationValue:details.value,durationUnit:details.unit,createdAt:Date.now()},employee);};
}

