function renderGeneric(label){$("#page-content").innerHTML=`${hero(label,`مساحة منظمة لإنشاء ومراجعة واعتماد ${label}.`,'<button class="primary">＋ إنشاء جديد</button>')}<div class="kpis"><article><i>▤</i><div><small>إجمالي السجلات</small><b>24</b></div></article><article><i>◷</i><div><small>بانتظار الاعتماد</small><b>6</b></div></article><article><i>✓</i><div><small>مكتمل</small><b>18</b></div></article></div><div class="documents"><h3>أحدث السجلات</h3>${["اعتماد تحديث السياسات الداخلية","مراجعة بيانات الحضور الشهرية","تعميم تنظيم الإجازات"].map((x,i)=>`<div><i>▤</i><span><b>${x}</b><small>الإدارة العامة · منذ ${i+1} أيام</small></span><em>${i===1?"قيد المراجعة":"معتمد"}</em></div>`).join("")}</div>`;}

function localToday(){return localDateKey(new Date());}
function attendanceTime(timestamp){if(!timestamp)return"—";return new Date(Number(timestamp)).toLocaleTimeString("ar-KW",{hour:"2-digit",minute:"2-digit",hour12:true});}
function attendanceDate(date){return leaveDateText(date);}
function durationText(minutes){if(!Number.isFinite(minutes)||minutes<=0)return"—";return`${String(Math.floor(minutes/60)).padStart(2,"0")}:${String(Math.round(minutes%60)).padStart(2,"0")}`;}
function scheduleBounds(date,employeeId){const assignments=Object.values(state.schedules?.[date]?.assignments||{}).filter(item=>item.employeeId===employeeId&&item.from&&item.to);if(!assignments.length)return null;const from=Math.min(...assignments.map(item=>{const [h,m]=String(item.from).split(":").map(Number);return h*60+m;})),to=Math.max(...assignments.map(item=>{const [h,m]=String(item.to).split(":").map(Number);return h*60+m;}));return{from,to};}
function minutesOf(timestamp){const date=new Date(Number(timestamp));return date.getHours()*60+date.getMinutes();}
function attendanceRows(filter=state.attendanceFilter||{}){const start=filter.startDate||localToday(),end=filter.endDate||localToday(),employeeId=filter.employeeId||"";const rows=[];Object.entries(state.attendance||{}).forEach(([date,employeeLogs])=>{if(date<start||date>end)return;Object.entries(employeeLogs||{}).forEach(([id,logs])=>{if(employeeId&&id!==employeeId)return;const events=Object.values(logs||{}).filter(Boolean).sort((a,b)=>Number(a.timestamp||0)-Number(b.timestamp||0));if(!events.length)return;const checkIn=events.find(item=>item.type==="checkIn")||null,checkOut=[...events].reverse().find(item=>item.type==="checkOut")||null,bounds=scheduleBounds(date,id),inMinutes=checkIn?minutesOf(checkIn.timestamp):null,outMinutes=checkOut?minutesOf(checkOut.timestamp):null;rows.push({date,employeeId:id,employee:state.employees.find(item=>item.id===id),checkIn,checkOut,firstTimestamp:Number(events[0].timestamp||0),late:bounds&&inMinutes!==null?Math.max(0,inMinutes-bounds.from):0,early:bounds&&outMinutes!==null?Math.max(0,bounds.to-outMinutes):0,lateOut:bounds&&outMinutes!==null?Math.max(0,outMinutes-bounds.to):0,place:checkIn?.branchName||checkOut?.branchName||""});});});return rows.sort((a,b)=>a.firstTimestamp-b.firstTimestamp);}
function attendanceTable(rows){return rows.length?`<div class="attendance-table-wrap"><table class="attendance-table"><thead><tr><th>اسم الموظف</th><th>التاريخ</th><th>وقت الدخول</th><th>وقت الخروج</th><th>تأخير</th><th>خروج مبكر</th><th>خروج متأخر</th></tr></thead><tbody>${rows.map(row=>`<tr><td><b>${escapeHtml(row.employee?.fullName||"موظف غير معروف")}</b>${row.place?`<small>${escapeHtml(row.place)}</small>`:""}</td><td>${attendanceDate(row.date)}</td><td>${attendanceTime(row.checkIn?.timestamp)}</td><td>${attendanceTime(row.checkOut?.timestamp)}</td><td class="${row.late?"metric-warn":""}">${durationText(row.late)}</td><td class="${row.early?"metric-warn":""}">${durationText(row.early)}</td><td class="${row.lateOut?"metric-good":""}">${durationText(row.lateOut)}</td></tr>`).join("")}</tbody></table></div>`:`<div class="attendance-empty"><i>◷</i><b>لا توجد بصمات ضمن الفترة المحددة</b></div>`;}
function reportFilters(){return state.attendanceFilter||{employeeId:"",startDate:localToday(),endDate:localToday()};}
function renderAttendanceReport(){const filter=reportFilters();state.attendanceFilter=filter;$("#page-content").innerHTML=`<section class="attendance-report"><div class="attendance-report-head"><div><span class="eyebrow">الحضور والانصراف</span><h1>تقرير البصمة</h1></div><div class="attendance-export-actions"><button id="attendance-excel" class="secondary">تحميل Excel</button><button id="attendance-pdf" class="primary">تحميل PDF</button></div></div><section class="attendance-filters"><label>الموظف<select id="attendance-employee"><option value="">جميع الموظفين</option>${state.employees.map(employee=>`<option value="${escapeHtml(employee.id)}" ${filter.employeeId===employee.id?"selected":""}>${escapeHtml(employee.fullName)}</option>`).join("")}</select></label><label>من تاريخ<input id="attendance-start" type="date" value="${filter.startDate}"></label><label>إلى تاريخ<input id="attendance-end" type="date" value="${filter.endDate}"></label><button id="attendance-apply" class="primary">عرض التقرير</button></section><section id="attendance-report-body" class="attendance-report-body"><div class="attendance-loader"><div><i></i><i></i><i></i></div><b>جاري جلب بيانات البصمة لليوم...</b><span>نرتب عمليات الحضور من الأقدم إلى الأحدث</span></div></section></section>`;$("#attendance-apply").onclick=applyAttendanceFilter;$("#attendance-excel").onclick=exportAttendanceExcel;$("#attendance-pdf").onclick=exportAttendancePdf;clearTimeout(attendanceRenderTimer);attendanceRenderTimer=setTimeout(refreshAttendanceReport,650);}
function applyAttendanceFilter(){const startDate=$("#attendance-start").value||localToday(),endDate=$("#attendance-end").value||startDate;if(endDate<startDate){showToast("تاريخ النهاية يجب أن يكون بعد تاريخ البداية.");return;}state.attendanceFilter={employeeId:$("#attendance-employee").value,startDate,endDate};refreshAttendanceReport();}
function refreshAttendanceReport(){const body=$("#attendance-report-body");if(!body)return;const rows=attendanceRows();body.innerHTML=`<div class="attendance-summary"><span>عدد الموظفين الذين بصموا: <b>${rows.length}</b></span><span>الفترة: <b>${attendanceDate(state.attendanceFilter.startDate)} — ${attendanceDate(state.attendanceFilter.endDate)}</b></span></div>${attendanceTable(rows)}`;}
function excelRows(rows){return rows.map(row=>({"اسم الموظف":row.employee?.fullName||"موظف غير معروف","التاريخ":attendanceDate(row.date),"وقت الدخول":attendanceTime(row.checkIn?.timestamp),"وقت الخروج":attendanceTime(row.checkOut?.timestamp),"تأخير":durationText(row.late),"خروج مبكر":durationText(row.early),"خروج متأخر":durationText(row.lateOut)}));}
function exportAttendanceExcel(){const rows=attendanceRows();if(!rows.length){showToast("لا توجد بيانات لتصديرها.");return;}const data=excelRows(rows);if(window.XLSX){const sheet=window.XLSX.utils.json_to_sheet(data),workbook=window.XLSX.utils.book_new();window.XLSX.utils.book_append_sheet(workbook,sheet,"تقرير البصمة");window.XLSX.writeFile(workbook,`تقرير البصمة ${state.attendanceFilter.startDate} - ${state.attendanceFilter.endDate}.xlsx`);return;}const header=Object.keys(data[0]),csv="\ufeff"+[header,...data.map(row=>header.map(key=>`\"${String(row[key]).replaceAll('"','""')}\"`).join(","))].join("\n"),url=URL.createObjectURL(new Blob([csv],{type:"text/csv;charset=utf-8"})),link=document.createElement("a");link.href=url;link.download=`تقرير البصمة ${state.attendanceFilter.startDate}.csv`;link.click();URL.revokeObjectURL(url);}
function reportLogos(){const company=state.settings.companyLogoUrl||state.settings.companyLogoDataUrl;return`<div class="attendance-pdf-logos"><span>${company?`<img src="${escapeHtml(company)}" crossorigin="anonymous" alt="شعار المنشأة">`:""}</span><img src="rakaez-mark.png" crossorigin="anonymous" alt="شعار ركائز"></div>`;}
async function exportAttendancePdf(){const rows=attendanceRows();if(!rows.length){showToast("لا توجد بيانات لتصديرها.");return;}if(!window.html2canvas||!window.jspdf){showToast("تعذر تجهيز ملف PDF، أعد المحاولة بعد اكتمال تحميل الصفحة.");return;}const root=document.createElement("div");root.className="attendance-pdf-render";root.innerHTML=`${reportLogos()}<h1>تقرير البصمة</h1><p>${attendanceDate(state.attendanceFilter.startDate)} — ${attendanceDate(state.attendanceFilter.endDate)}</p>${attendanceTable(rows)}`;document.body.append(root);try{const canvas=await window.html2canvas(root,{scale:2,backgroundColor:"#fff",useCORS:true}),{jsPDF}=window.jspdf,pdf=new jsPDF({orientation:"landscape",unit:"mm",format:"a4"});pdf.addImage(canvas.toDataURL("image/png"),"PNG",0,0,297,210);pdf.save(`تقرير البصمة ${state.attendanceFilter.startDate} - ${state.attendanceFilter.endDate}.pdf`);}finally{root.remove();}}

function renderSettings(){const logo=state.settings.companyLogoUrl||state.settings.companyLogoDataUrl;$("#page-content").innerHTML=`<section class="settings-page"><div class="settings-heading"><span class="eyebrow">إعدادات المنشأة</span><h1>إعدادات المنشأة</h1></div><section class="company-logo-setting"><div><span class="settings-index">01</span><h2>شعار المنشأة</h2></div><label class="company-logo-upload ${logo?"has-logo":""}" for="company-logo-input"><input id="company-logo-input" type="file" accept="image/png"><span class="company-logo-preview">${logo?`<img src="${escapeHtml(logo)}" alt="شعار المنشأة">`:'<i>▧</i>'}</span><b>${logo?"تغيير شعار المنشأة":"رفع شعار PNG"}</b></label><p id="company-logo-status" class="settings-status"></p></section><section class="fingerprint-settings-link"><div><span class="settings-index">02</span><h2>أماكن البصمة</h2><p>إدارة الباركود والإحداثيات ونطاق التحقق.</p></div><button id="open-fingerprint-places" class="primary">إدارة أماكن البصمة</button></section></section>`;$("#open-fingerprint-places").onclick=()=>{state.page="fingerprint-places";renderPage();};$("#company-logo-input").onchange=saveCompanyLogo;}
async function saveCompanyLogo(event){const file=event.target.files?.[0],status=$("#company-logo-status");if(!file)return;if(file.type!=="image/png"){status.textContent="يرجى اختيار ملف PNG فقط.";status.className="settings-status error";return;}if(file.size>1024*1024){status.textContent="اجعل حجم الشعار أقل من 1 ميغابايت.";status.className="settings-status error";return;}try{const companyLogoDataUrl=await new Promise((resolve,reject)=>{const reader=new FileReader();reader.onload=()=>resolve(reader.result);reader.onerror=()=>reject(new Error("تعذر قراءة ملف الشعار"));reader.readAsDataURL(file);});state.settings={...state.settings,companyLogoDataUrl,companyLogoUrl:""};if(!state.demo&&state.user)await set(ref(db,"organizations/default/settings"),{...state.settings,updatedAt:Date.now()});showToast("تم حفظ شعار المنشأة");renderSettings();}catch(error){status.textContent=error.message||"تعذر حفظ الشعار.";status.className="settings-status error";}}
function placeCard(place){const location=place.location||{},coordinates=Number.isFinite(Number(location.lat))&&Number.isFinite(Number(location.lng))?`${Number(location.lat).toFixed(6)}, ${Number(location.lng).toFixed(6)}`:"غير محددة";return`<article class="fingerprint-place-card"><div><span>مكان البصمة</span><h3>${escapeHtml(place.title||place.branchName||"مكان بلا اسم")}</h3><p>${escapeHtml(place.branchName||place.branchKey||"")}</p></div><dl><div><dt>الباركود</dt><dd>${escapeHtml(place.barcodeValue||place.barcodeToken||"—")}</dd></div><div><dt>الإحداثيات</dt><dd>${coordinates}</dd></div><div><dt>النطاق</dt><dd>${escapeHtml(place.radiusMeters||"—")} متر</dd></div></dl><button data-edit-place="${escapeHtml(place.id)}" class="secondary">تعديل</button></article>`;}
function renderFingerprintPlaces(){$("#page-content").innerHTML=`<section class="fingerprint-places-page"><div class="attendance-report-head"><div><span class="eyebrow">إعدادات البصمة</span><h1>أماكن البصمة</h1></div><div><button id="back-settings" class="secondary">→ الإعدادات</button><button id="add-fingerprint-place" class="primary">＋ إضافة مكان</button></div></div><section class="fingerprint-places-grid">${state.fingerprintPlaces.length?state.fingerprintPlaces.map(placeCard).join(""):'<div class="attendance-empty"><b>لا توجد أماكن بصمة بعد</b></div>'}</section></section>`;$("#back-settings").onclick=()=>{state.page="settings";renderPage();};$("#add-fingerprint-place").onclick=()=>openFingerprintPlaceModal();document.querySelectorAll("[data-edit-place]").forEach(button=>button.onclick=()=>openFingerprintPlaceModal(button.dataset.editPlace));}
function fingerprintPlaceForm(place={}){const location=place.location||{};return`<div class="modal-backdrop"><section class="modal fingerprint-place-modal"><header><div><span>أماكن البصمة</span><h3>${place.id?"تعديل مكان البصمة":"إضافة مكان بصمة"}</h3></div><button type="button" class="modal-close">×</button></header><form id="fingerprint-place-form"><div class="editor-grid"><label>اسم المكان<input name="title" value="${escapeHtml(place.title||"")}" required></label><label>الفرع<select name="branchKey"><option value="hawalli" ${["hawalli","surra"].includes(place.branchKey)?"selected":""}>حولي</option><option value="abu_al_hasaniya" ${["abu_al_hasaniya","abulhasania"].includes(place.branchKey)?"selected":""}>أبو الحصانية</option><option value="yarmouk" ${place.branchKey==="yarmouk"?"selected":""}>اليرموك</option></select></label><label class="wide-field">قيمة الباركود<input name="barcodeValue" dir="ltr" value="${escapeHtml(place.barcodeValue||"")}" required></label><label>خط العرض<input name="latitude" dir="ltr" inputmode="decimal" value="${escapeHtml(location.lat||"")}" required></label><label>خط الطول<input name="longitude" dir="ltr" inputmode="decimal" value="${escapeHtml(location.lng||"")}" required></label><label>النطاق بالمتر<input name="radiusMeters" inputmode="numeric" value="${escapeHtml(place.radiusMeters||30)}" required></label></div><p id="fingerprint-place-error" class="form-message error hidden"></p><footer><button type="button" class="secondary modal-cancel">إلغاء</button><button class="primary">حفظ المكان</button></footer></form></section></div>`;}
function openFingerprintPlaceModal(id=""){const place=state.fingerprintPlaces.find(item=>item.id===id)||{},root=$("#modal-root");root.innerHTML=fingerprintPlaceForm(place);const close=()=>root.innerHTML="";$(".modal-close").onclick=$(".modal-cancel").onclick=close;$("#fingerprint-place-form").onsubmit=async event=>{event.preventDefault();const data=Object.fromEntries(new FormData(event.target)),branchName={hawalli:"حولي",abu_al_hasaniya:"أبو الحصانية",yarmouk:"اليرموك"}[data.branchKey],barcodeValue=data.barcodeValue.trim(),barcodeToken=barcodeValue.startsWith("HRMS-BASMA:")?barcodeValue.slice("HRMS-BASMA:".length):barcodeValue,error=$("#fingerprint-place-error");if(!Number.isFinite(Number(data.latitude))||!Number.isFinite(Number(data.longitude))||Number(data.radiusMeters)<=0){error.textContent="تحقق من الإحداثيات والنطاق.";error.classList.remove("hidden");return;}const record={...place,id:place.id||crypto.randomUUID(),mode:"barcode",title:data.title.trim(),branchKey:data.branchKey,branchName,barcodeValue,barcodeToken,location:{lat:Number(data.latitude),lng:Number(data.longitude)},radiusMeters:Number(data.radiusMeters),updatedAt:Date.now()};try{await set(ref(db,`organizations/default/fingerprintPlaces/${record.id}`),record);close();showToast("تم حفظ مكان البصمة");}catch(err){error.textContent=err.message||"تعذر حفظ المكان.";error.classList.remove("hidden");}};}

function renderFingerprintPlaces(){const importButton=!state.fingerprintPlaces.length?'<button id="import-legacy-places" class="secondary">نقل الأماكن والباركودات الأصلية</button>':"";$("#page-content").innerHTML=`<section class="fingerprint-places-page"><div class="attendance-report-head"><div><span class="eyebrow">إعدادات البصمة</span><h1>أماكن البصمة</h1></div><div><button id="back-settings" class="secondary">→ الإعدادات</button>${importButton}<button id="add-fingerprint-place" class="primary">＋ إضافة مكان</button></div></div><section class="fingerprint-places-grid">${state.fingerprintPlaces.length?state.fingerprintPlaces.map(placeCard).join(""):'<div class="attendance-empty"><b>لا توجد أماكن بصمة بعد</b></div>'}</section></section>`;$("#back-settings").onclick=()=>{state.page="settings";renderPage();};$("#add-fingerprint-place").onclick=()=>openFingerprintPlaceModal();$("#import-legacy-places")&&( $("#import-legacy-places").onclick=migrateLegacyFingerprintPlaces );document.querySelectorAll("[data-edit-place]").forEach(button=>button.onclick=()=>openFingerprintPlaceModal(button.dataset.editPlace));}
async function migrateLegacyFingerprintPlaces(){const button=$("#import-legacy-places");if(button){button.disabled=true;button.textContent="جاري النقل...";}try{await set(ref(db,"organizations/default/fingerprintPlaces"),LEGACY_FINGERPRINT_PLACES);showToast("تم نقل أماكن البصمة والباركودات الأصلية إلى ركائز");}catch(error){showToast(error.message||"تعذر نقل أماكن البصمة.");if(button){button.disabled=false;button.textContent="نقل الأماكن والباركودات الأصلية";}}}

$("#logout-btn").onclick=async()=>{stopSessionSecurity();sessionStorage.removeItem(AUTH_SESSION_MARKER);if(state.demo){state.demo=false;state.bound=false;openAuth();}else await signOut(auth);};
$("#global-search").oninput=e=>{state.search=e.target.value;if(state.page==="employees")renderEmployees();};
$("[data-open-notifications]").onclick=()=>{state.page="notifications";renderNav();renderPage();};
initialize().catch(error=>{$("#loading").innerHTML=`<b>تعذر تشغيل النظام</b><p>${escapeHtml(error.message)}</p>`;});
